import Home from './pages/Home';
import Events from './pages/Events'

const router = createBrowserRouter([
  {path: '/', element: <Home/> },
  {path: '/events', element: <Events/>},
  {path: '/events/:eventId', element: <EventDetail/>}
]);

function App() {
  return <div></div>
}

export default App;
